module top_module(Address, Write_data, Read_data, MemRead, MemWrite, clk);input [31:0] Address, Write_data;
    input MemRead, MemWrite, clk;
    output reg [31:0] Read_data;
    reg [31:0] data_store[31:0];

    always @ (posedge clk)
    begin
        if (MemWrite) data_store[Address >> 2] = Write_data; 
    end

    always @ (negedge clk)
    begin
        if (MemRead) Read_data = data_store[Address >> 2];
    end

endmodule
